{
  "short_persona": "A nature photographer who appreciates the quietness of the bicycle shop and often stops by to chat",
  "name": "Miguel Santiago Rivera",
  "age": 37,
  "gender": "Male",
  "sexual_orientation": "Heterosexual",
  "race_ethnicity": "Mexican-American (Latino/Hispanic)",
  "personality": {
    "traits": [
      "thoughtful",
