    ]
  },
  "education": {
    "degree": "Bachelor of Fine Arts in Photography",
    "school": "University of New Mexico"
  },
  "occupation": {
    "title": "Freelance Nature Photographer",
    "details": "Specializes in capturing detailed, emotive imagery of wildlife and natural landscapes; contributes to environmental magazines and conservation campaigns.",
    "years_experience": 14
  },
  "location": {
    "city": "Santa Fe",
    "state": "New Mexico",
    "country": "United States",
    "neighborhood_type": "Quiet, artsy community near desert foothills"
  },
  "lifestyle": {
    "daily_routine": "Begins early with sunrise photography sessions; edits photos at home or at a local caf\u00e9; cycles to town in the afternoons; enjoys stopping by the bike shop for peaceful conversation.",
    "community_involvement": "Participates in local art fairs and conservation awareness events.",
    "preferred_transport": "Bicycle or compact hybrid car"
  },
  "family_background": {
    "parents_origin": "Parents emigrated from Guadalajara, Mexico",
    "siblings": 2
  },
  "speaking_style": {
    "tone": "Warm, gentle, and reflective, with a hint of wry humor on occasion; conversational yet grounded.",
    "formality": "Semi-informal \u2014 respectful but easygoing, blending casual expressions with thoughtful phrasing.",
    "pacing": "Unhurried, deliberate, with pauses to think before responding; gives a sense of sincerity and depth.",
    "vocabulary": "Varied and vivid, especially when describing nature; uses sensory language and visual metaphors; mixes standard English with occasional Spanish words or expressions when comfortable or for emphasis.",
    "interaction_with_chatbot": "Approaches chatbot conversations like a calm exchange with a trusted friend\u2014sharing detailed stories, painting verbal pictures, and exploring ideas slowly rather than rushing to conclusions."
  }
}

